// Init run context
const now = new Date();
const run_id = `run_${now.toISOString().slice(0,10)}_${now.getTime()}`;
const started_at = now.toISOString();

// Time window: previous calendar day in Europe/Rome (with a safety margin back to 36h)
const msInDay = 24*3600*1000;
const toMs = now.getTime();
const fromMs = toMs - 36*3600*1000;
return [{ json: {
  run_id,
  started_at,
  window_from: new Date(fromMs).toISOString(),
  window_to: new Date(toMs).toISOString(),
  spreadsheetId: $('Config').first().json.spreadsheetId
}}];

// Parse rows into structured source objects, keep enabled only.
const values = ($json.values || []);
if (!values.length) return [];
const [headers, ...rows] = values;
const idx = Object.fromEntries(headers.map((h,i)=>[h,i]));
const sources = rows.map(r => ({
  source_id: r[idx.source_id]||'',
  name: r[idx.name]||'',
  url: r[idx.url]||'',
  type: (r[idx.type]||'').toLowerCase(),
  tier: r[idx.tier]||'tier2',
  enabled: String(r[idx.enabled]||'').toLowerCase() === 'true',
  topic_scope: r[idx.topic_scope]||'',
  trust_score: parseFloat(r[idx.trust_score]||'0.5'),
  notes: r[idx.notes]||''
})).filter(s => s.enabled && s.url);
return sources.map(s => ({ json: { ...s } }));

// Normalize RSS items into unified shape
const items = $input.all();
const out = [];
for (const it of items) {
  // The source info must be re-looked-up; n8n's 'pairedItem' tracks it, but to be safe:
  // The RSS node returns items each with own fields; source is the upstream triggering item.
  // We use $('Parse Sources') pairing indirectly — since RSS node explodes per item, we lose direct source context.
  // Workaround: read from runtime via node linkage is fragile. Instead: we preserve source via fetch-time injection below in helper nodes.
  const r = it.json;
  out.push({
    title: r.title || '',
    url: r.link || r.url || '',
    summary: r.contentSnippet || r.content || r.description || '',
    content_text: r.content || '',
    published_at: r.isoDate || r.pubDate || r.published || null,
    raw_type: 'rss'
  });
}
return out.map(o => ({ json: o }));

// Very light HTML normalization: extract <a href> + inner text blocks that look like article titles.
const items = $input.all();
const out = [];
for (const it of items) {
  const body = String(it.json.data || it.json.body || it.json.response || it.json || '');
  // naive anchor extraction
  const anchorRe = /<a[^>]+href="([^"]+)"[^>]*>([\s\S]*?)<\/a>/gi;
  let m, count=0;
  while ((m = anchorRe.exec(body)) !== null && count < 40) {
    const href = m[1];
    const text = m[2].replace(/<[^>]+>/g,'').replace(/\s+/g,' ').trim();
    if (text && text.length > 20 && text.length < 220 && /^https?:\/\//.test(href)) {
      out.push({
        title: text,
        url: href,
        summary: '',
        content_text: '',
        published_at: null,
        raw_type: 'html'
      });
      count++;
    }
  }
}
return out.map(o => ({ json: o }));

// Aggregate, canonicalize, dedupe, date-filter
const run = $('Init Run').first().json;
const windowFrom = new Date(run.window_from).getTime();
const windowTo = new Date(run.window_to).getTime();

function canonical(url){
  if (!url) return '';
  try {
    const u = new URL(url);
    u.hash='';
    const drop = new Set(['utm_source','utm_medium','utm_campaign','utm_term','utm_content','gclid','fbclid','ref','ref_src']);
    const params=[...u.searchParams.entries()].filter(([k])=>!drop.has(k.toLowerCase()));
    u.search = new URLSearchParams(params).toString();
    return u.toString().replace(/\/$/, '').toLowerCase();
  } catch(e){ return String(url).toLowerCase(); }
}
function normTitle(t){ return String(t||'').toLowerCase().replace(/[^a-z0-9 ]+/g,' ').replace(/\s+/g,' ').trim(); }

const raw = $input.all().map(i => i.json).filter(x => x && (x.title || x.url));
const dedupMap = new Map();
let rawCount=0, dateKept=0;
for (const r of raw) {
  rawCount++;
  const pubMs = r.published_at ? new Date(r.published_at).getTime() : null;
  const inWindow = pubMs == null ? true : (pubMs >= windowFrom && pubMs <= windowTo);
  if (!inWindow) continue;
  dateKept++;
  const cu = canonical(r.url);
  const nt = normTitle(r.title);
  const key = cu || `t:${nt}`;
  const prev = dedupMap.get(key);
  if (!prev) { dedupMap.set(key, r); continue; }
  // Prefer official (tier1) / higher trust — but we lost source here. Keep earliest published or the one with a summary.
  if ((r.summary||'').length > (prev.summary||'').length) dedupMap.set(key, r);
}
const deduped = Array.from(dedupMap.values()).map((r, i) => ({
  item_id: `i_${run.run_id}_${i}`,
  title: r.title || '',
  url: r.url || '',
  canonical_url: canonical(r.url),
  source_name: r.source_name || '',
  source_tier: r.source_tier || '',
  published_at: r.published_at || null,
  summary: r.summary || '',
  content_text: (r.content_text||'').slice(0, 1800),
  raw_type: r.raw_type || '',
  primary_topic: ''
}));

return [{ json: {
  run_id: run.run_id,
  started_at: run.started_at,
  window_from: run.window_from,
  window_to: run.window_to,
  raw_items_count: rawCount,
  dated_kept: dateKept,
  deduped_count: deduped.length,
  items: deduped
}}];

// Build one LLM batch scoring request. Cap items to first 40 to control tokens.
const cfg = $('Config').first().json;
const data = $json;
const items = (data.items || []).slice(0, 40);

if (!items.length) {
  return [{ json: { ...data, skip_llm: true, scored_items: [] } }];
}

const system = `Sei un analista senior di AI/business. Valuti news AI per un pubblico italiano di imprenditori, PMI e liberi professionisti. Output: SOLO JSON valido.`;

const criteria = `Priorità: 1) impatto su mercato 2) impatto su business 3) shareability 4) rilevanza Italia 5) interesse nicchia 6) autorità fonte 7) novità. Penalizza: minor updates, contenuti troppo tecnici per sviluppatori, bassa rilevanza business, hype vuoto.`;

const userPayload = {
  task: 'score_items',
  criteria,
  required_output_schema: {
    scores: [{
      item_id: 'string',
      candidate_score: 'number 0-10',
      publishable_score: 'number 0-10',
      confidence: 'number 0-1',
      primary_topic: 'string',
      rationale: 'string (1 frase)'
    }]
  },
  items: items.map(it => ({
    item_id: it.item_id,
    title: it.title,
    url: it.url,
    source_name: it.source_name,
    source_tier: it.source_tier,
    published_at: it.published_at,
    summary: (it.summary||'').slice(0,600)
  }))
};

const body = {
  model: cfg.modelMain,
  temperature: 0.1,
  max_tokens: 3000,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system },
    { role: 'user', content: JSON.stringify(userPayload) }
  ]
};

return [{ json: { ...data, openrouter_body: body, items_for_scoring: items } }];

// Parse scores and merge with items, decide run mode, shortlist, and fetch fallback library if needed.
const cfg = $('Config').first().json;
const dataNode = $('Dedupe + Filter').first().json;
const items = dataNode.items || [];

function safeParse(s){ try { return JSON.parse(s); } catch(e){ return null; } }
let parsed = null;
const resp = $json;
const choices = resp.choices || (resp.body && resp.body.choices);
if (choices && choices[0]) parsed = safeParse(choices[0].message?.content);
const scoresById = {};
if (parsed && Array.isArray(parsed.scores)) {
  for (const s of parsed.scores) scoresById[s.item_id] = s;
}

const enriched = items.map(it => {
  const s = scoresById[it.item_id] || {};
  return {
    ...it,
    candidate_score: typeof s.candidate_score==='number' ? s.candidate_score : 0,
    publishable_score: typeof s.publishable_score==='number' ? s.publishable_score : 0,
    confidence: typeof s.confidence==='number' ? s.confidence : 0,
    primary_topic: s.primary_topic || '',
    rationale: s.rationale || ''
  };
});

// Apply thresholds
const candMin = Number(cfg.candidateMin)||7;
const pubMin  = Number(cfg.publishableMin)||8;
const confMin = Number(cfg.confidenceMin)||0.75;

const publishable = enriched
  .filter(x => x.candidate_score >= candMin && x.publishable_score >= pubMin && x.confidence >= confMin)
  .sort((a,b) => (b.publishable_score - a.publishable_score) || (b.confidence - a.confidence));

const candidates = enriched
  .filter(x => x.candidate_score >= candMin && !publishable.includes(x))
  .sort((a,b) => b.candidate_score - a.candidate_score);

// Mode selection
let mode;
if (!enriched.length) mode = 'HARD_STOP';
else if (publishable.length >= 3) mode = 'FULL_NEWS';
else if (publishable.length >= 1) mode = 'HYBRID';
else if (candidates.length >= 2) mode = 'MONITOR_ONLY';
else mode = 'FALLBACK';

const selected = publishable.slice(0,3);
const backup = candidates.slice(0,2);

// Shortlist for digest
const shortlist = [...selected, ...candidates.slice(0, Math.max(0, 5-selected.length))]
  .slice(0,5)
  .map(x => ({ title: x.title, reason: x.rationale || `score ${x.publishable_score}` }));

return [{ json: {
  run_id: dataNode.run_id,
  started_at: dataNode.started_at,
  mode,
  enriched,
  selected_items: selected,
  backup_items: backup,
  shortlist,
  meta: {
    sources_total: (enriched.length>0 ? 'see-logs' : 0),
    sources_failed: 0,
    raw_items_count: dataNode.raw_items_count,
    deduped_count: dataNode.deduped_count,
    selected_count: selected.length
  }
}}];

// Attach fallback items when needed. Keep everything in one envelope for WF2 and WF3.
const intel = $('Parse Scores + Select Mode').first().json;
const fb = $json;
const fbRows = fb.values || [];
let fallbacks = [];
if (fbRows.length > 1) {
  const [h, ...rows] = fbRows;
  const idx = Object.fromEntries(h.map((k,i)=>[k,i]));
  fallbacks = rows.map(r => ({
    fallback_id: r[idx.fallback_id]||'',
    category: r[idx.category]||'',
    title: r[idx.title]||'',
    angle: r[idx.angle]||'',
    target: r[idx.target]||'',
    priority: r[idx.priority]||'medium',
    enabled: String(r[idx.enabled]||'').toLowerCase()==='true'
  })).filter(x => x.enabled);
  // Priority ordering
  const rank = { high: 0, medium: 1, low: 2 };
  fallbacks.sort((a,b) => (rank[a.priority]??1) - (rank[b.priority]??1));
}

const envelope = {
  run_id: intel.run_id,
  started_at: intel.started_at,
  mode: intel.mode,
  selected_items: intel.selected_items,
  backup_items: intel.backup_items,
  fallback_items: fallbacks.slice(0,3),
  shortlist: intel.shortlist,
  meta: intel.meta,
  note: ''
};

// Build rows for ranked_items_history
const rows = (intel.enriched || []).map(x => [
  intel.run_id,
  x.item_id,
  x.title,
  x.url,
  x.source_name || '',
  x.published_at || '',
  x.primary_topic || '',
  x.candidate_score,
  x.publishable_score,
  x.confidence,
  (intel.selected_items||[]).some(s => s.item_id === x.item_id) ? 'yes' : 'no',
  x.rationale || ''
]);

return [{ json: {
  spreadsheetId: $('Config').first().json.spreadsheetId,
  range: 'ranked_items_history!A:L',
  values: rows,
  envelope
}}];
